const json = (o,s=200)=>new Response(JSON.stringify(o),{status:s,headers:{"content-type":"application/json","cache-control":"no-store"}});
async function sendEmail(env,to,subject,html){ if(!env.RESEND_KEY||!to) return {skipped:true}; try{ const r=await fetch("https://api.resend.com/emails",{method:"POST",headers:{"Authorization":"Bearer "+env.RESEND_KEY,"content-type":"application/json"},body:JSON.stringify({from:(env.MAIL_FROM||"Spire Scope <onboarding@resend.dev>"),to:[to],subject:subject,html:html})}); return {ok:r.ok,status:r.status}; }catch(e){ return {ok:false,error:String(e)}; } }
function digestHtml(jobName,name,pp){ const e=(x)=>String(x||"").replace(/[&<>]/g,function(c){return ({"&":"&amp;","<":"&lt;",">":"&gt;"})[c];}); let h='<div style="font-family:system-ui,Arial;font-size:14px;color:#222"><p>Hi '+e(name)+',</p><p>Your update on <b>'+e(jobName)+'</b>:</p>'; if(pp.tasks.length){ h+='<p><b>Tasks due</b></p><ul>'; pp.tasks.forEach(function(t){ h+='<li>'+e(t.tid)+' \u2014 '+(t.days<0?('<b style="color:#a3251d">'+(-t.days)+' days overdue</b>'):(t.days===0?'<b>due today</b>':'due '+e(t.due)))+'</li>'; }); h+='</ul>'; } if(pp.notes.length){ h+='<p><b>Notes for you</b></p><ul>'; pp.notes.forEach(function(n){ h+='<li>'+e(n.tid)+': '+e(n.text)+' <i>\u2014 '+e(n.by)+'</i></li>'; }); h+='</ul>'; } h+='<p style="color:#888;font-size:12px">Open the tracker to act on these.</p></div>'; return h; }
async function runDigest(env,kv,url){ const id=url.searchParams.get("job"); if(!id||!JOBS[id]) return json({error:"unknown job"},400); const state=(await kv.get("state:"+id,"json"))||{}; const assign=(await kv.get("assign:"+id,"json"))||{}; const notes=(await kv.get("notes:"+id,"json"))||{}; const roster=(await kv.get("roster:"+id,"json"))||[]; const emailBy={}; roster.forEach(function(p){ if(p.email) emailBy[p.name]=p.email; }); const today=new Date(); today.setHours(0,0,0,0); const per={}; Object.keys(assign).forEach(function(tid){ const a=assign[tid]; if(state[tid]&&state[tid].done) return; if(!a.due) return; const d=new Date(a.due+"T00:00:00"); const days=Math.round((d-today)/86400000); if(days<=1){ (a.to||[]).forEach(function(n){ (per[n]=per[n]||{tasks:[],notes:[]}).tasks.push({tid:tid,due:a.due,days:days}); }); } }); Object.keys(notes).forEach(function(tid){ (notes[tid]||[]).forEach(function(nt){ if(nt.done) return; (nt.to||[]).forEach(function(n){ if(emailBy[n]){ (per[n]=per[n]||{tasks:[],notes:[]}).notes.push({tid:tid,text:nt.text,by:nt.by}); } }); }); }); const preview=[]; const sent=[]; for(const name of Object.keys(per)){ const pp=per[name]; if(!pp.tasks.length&&!pp.notes.length) continue; const email=emailBy[name]||null; preview.push({name:name,email:email,tasks:pp.tasks.length,notes:pp.notes.length}); if(email){ const r=await sendEmail(env,email,"["+JOBS[id].name+"] "+pp.tasks.length+" due \u00b7 "+pp.notes.length+" notes",digestHtml(JOBS[id].name,name,pp)); sent.push(Object.assign({name:name,email:email},r)); } } return json({digest:true,job:id,mailer:env.RESEND_KEY?"resend":"none \u2014 set RESEND_KEY env var to actually send",recipients:preview,sent:sent}); }
const total = d => Object.values(d.counts).reduce((a,b)=>a+b,0);
function idIndex(data,add){const m={};const PREFIX=["AD","AF","MW","ME","EL","PL","FA","FS","ST"];(data.trades||[]).forEach(function(t,ti){const code=t.code||PREFIX[ti]||("T"+ti);let n=0;(t.sections||[]).forEach(function(sec){(sec.tables||[]).forEach(function(tab){(tab.rows||[]).forEach(function(r){const ne=r.filter(function(x){return (""+x).trim();});if(ne.length===1&&r.length>1)return;n++;m[code+"-"+String(n).padStart(3,"0")]={desc:(r[1]||r[0]||"").slice(0,120),code:code};});});});});((add&&add.tasks)||[]).forEach(function(t){if(t.id)m[t.id]={desc:(t.desc||"").slice(0,120),code:t.code||"MAN"};});return m;}

function tradeMap(d){ const m={}; (d.trades||[]).forEach(t=>{ m[t.code]={name:t.name,count:t.count}; }); return m; }
function genCode(name, used){
  let letters=(name.match(/[A-Za-z]+/g)||["X"]).map(w=>w[0].toUpperCase());
  let code=(letters.join("").slice(0,2)) || "XX";
  if(code.length<2) code=((name.replace(/[^A-Za-z]/g,"").toUpperCase())+"X").slice(0,2);
  let c=code,i=1;
  while(used.has(c)){ c=(code[0]+String(i)); i++; if(i>9){ c=code+String(i); } }
  return c;
}

export async function onRequest(context){
  const { request, env } = context;
  const url=new URL(request.url);
  const PASS=(env.PASSCODE||"").toString();
  const isDigest=url.searchParams.get("digest");
  const digestOk=isDigest&&env.DIGEST_KEY&&url.searchParams.get("key")===env.DIGEST_KEY;
  if(!digestOk){ if(!PASS || (request.headers.get("x-pass")||"")!==PASS) return json({error:"unauthorized"},401); }
  const kv=env.SCOPE; if(!kv) return json({error:"KV namespace binding 'SCOPE' is missing"},500);

  if(url.searchParams.get("health")) return json({ok:true,files:!!env.FILES,kv:!!kv});
  if(request.method==="GET" && url.searchParams.get("file")){
    if(!env.FILES) return json({error:"file storage not connected"},500);
    const key=url.searchParams.get("file");
    const obj=await env.FILES.get(key);
    if(!obj) return new Response("not found",{status:404});
    const h=new Headers(); obj.writeHttpMetadata(h); h.set("Cache-Control","private, max-age=3600");
    const dl=url.searchParams.get("dl"); if(dl){ h.set("Content-Disposition",'attachment; filename="'+dl.replace(/[^A-Za-z0-9._-]/g,"_")+'"'); }
    return new Response(obj.body,{headers:h});
  }
  if(request.method==="POST" && url.searchParams.get("upload")){
    if(!env.FILES) return json({error:"file storage not connected"},500);
    const job=(url.searchParams.get("job")||"").toString(); if(!JOBS[job]) return json({error:"unknown job"},400);
    const name=(request.headers.get("x-filename")||"file").toString().slice(0,180);
    const ctype=request.headers.get("content-type")||"application/octet-stream";
    const body=await request.arrayBuffer();
    if(body.byteLength>52428800) return json({error:"file too large (50MB max)"},400);
    const rand=Date.now().toString(36)+Math.random().toString(36).slice(2,8);
    const safe=name.replace(/[^A-Za-z0-9._-]/g,"_");
    const key="files/"+job+"/"+rand+"-"+safe;
    await env.FILES.put(key,body,{httpMetadata:{contentType:ctype}});
    return json({ok:true,key:key,name:name,size:body.byteLength,type:ctype});
  }

  if(request.method==="GET"){
    if(isDigest) return await runDigest(env,kv,url);
    if(url.searchParams.get("list")){
      const jobs=[];
      for(const id of Object.keys(JOBS)){
        const st=(await kv.get("state:"+id,"json"))||{};
        const add=(await kv.get("add:"+id,"json"))||{trades:[],tasks:[]};
        const prio=(await kv.get("prio:"+id,"json"))||{};
        const idx=idIndex(JOBS[id].data,add);
        const todos=Object.keys(prio).filter(function(k){return prio[k]>0;}).map(function(k){return {id:k,code:(idx[k]&&idx[k].code)||(k.split("-")[0]||""),desc:(idx[k]&&idx[k].desc)||"",prio:prio[k],done:!!(st[k]&&st[k].done)};}).sort(function(a,b){return b.prio-a.prio;}).slice(0,60);
        jobs.push({id,name:JOBS[id].name,address:JOBS[id].address,
                   total: total(JOBS[id].data)+ (add.tasks?add.tasks.length:0),
                   done: Object.values(st).filter(v=>v&&v.done).length,
                   todos:todos});
      }
      return json({jobs,now:Date.now()});
    }
    const id=url.searchParams.get("job");
    if(!id||!JOBS[id]) return json({error:"unknown job"},400);
    const state=(await kv.get("state:"+id,"json"))||{};
    const log=(await kv.get("log:"+id,"json"))||[];
    const add=(await kv.get("add:"+id,"json"))||{trades:[],tasks:[]};
    const prio=(await kv.get("prio:"+id,"json"))||{};
    const notes=(await kv.get("notes:"+id,"json"))||{};
    const marks=(await kv.get("marks:"+id,"json"))||{};
    const roster=(await kv.get("roster:"+id,"json"))||[];
    const assign=(await kv.get("assign:"+id,"json"))||{};
    const rfis=(await kv.get("rfis:"+id,"json"))||{list:[],seq:0};
    const subs=(await kv.get("subs:"+id,"json"))||{list:[],seq:0};
    const logs=(await kv.get("logs:"+id,"json"))||{list:[]};
    const out={state,log:log.slice(-LOG_RETURN).reverse(),add,prio,notes,marks,roster,assign,rfis,subs,logs,now:Date.now()};
    if(url.searchParams.get("init")){out.data=JOBS[id].data;out.draw=DRAWMAP[id]||{};out.sheets=SHEETS[id]||{};out.details=DETAILS[id]||{};}
    return json(out);
  }

  if(request.method==="POST"){
    let b; try{b=await request.json();}catch{return json({error:"bad json"},400);}
    const id=(b.job||"").toString();
    if(!JOBS[id]) return json({error:"unknown job"},400);
    const data=JOBS[id].data;
    const user=(b.user||"Unknown").toString().slice(0,40);
    const ts=Date.now();
    let state=(await kv.get("state:"+id,"json"))||{};
    let log=(await kv.get("log:"+id,"json"))||[];
    let add=(await kv.get("add:"+id,"json"))||{trades:[],tasks:[]};
    let prio=(await kv.get("prio:"+id,"json"))||{};
    let notes=(await kv.get("notes:"+id,"json"))||{};
    let marks=(await kv.get("marks:"+id,"json"))||{};
    let roster=(await kv.get("roster:"+id,"json"))||[];
    let assign=(await kv.get("assign:"+id,"json"))||{};
    let rfis=(await kv.get("rfis:"+id,"json"))||{list:[],seq:0};
    let subs=(await kv.get("subs:"+id,"json"))||{list:[],seq:0};
    let logs=(await kv.get("logs:"+id,"json"))||{list:[]};

    if(b.action==="setprio"){
      const tid=(b.taskId||"").toString(); if(!tid) return json({error:"missing taskId"},400);
      let v=Math.round(Number(b.value)); if(!isFinite(v)) v=0;
      v=Math.max(0,Math.min(100,v));
      if(v<=0) delete prio[tid]; else prio[tid]=v;
      await kv.put("prio:"+id,JSON.stringify(prio));
      return json({ok:true});
    } else if(b.action==="toggle"){
      const tid=(b.taskId||"").toString(); if(!tid) return json({error:"missing taskId"},400);
      if(b.done) state[tid]={done:true,by:user,at:ts}; else delete state[tid];
      log.push({ts,user,id:tid,label:(b.label||"").toString().slice(0,90),action:b.done?"checked":"unchecked"});
      await kv.put("state:"+id,JSON.stringify(state));
    } else if(b.action==="clear"){
      const n=Object.keys(state).length; state={};
      log.push({ts,user,action:"cleared all",n});
      await kv.put("state:"+id,JSON.stringify(state));
    } else if(b.action==="addtrade"){
      const name=(b.name||"").toString().trim().slice(0,60); if(!name) return json({error:"missing name"},400);
      const used=new Set(Object.keys(tradeMap(data)).concat(add.trades.map(t=>t.code)));
      const code=genCode(name,used);
      const color=PALETTE[add.trades.length % PALETTE.length];
      const tr={code,name,color,by:user,at:ts};
      add.trades.push(tr);
      log.push({ts,user,action:"added trade",label:name+" ("+code+")"});
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));await kv.put("add:"+id,JSON.stringify(add));
      return json({ok:true,trade:tr});
    } else if(b.action==="addtask"){
      const code=(b.code||"").toString();
      const baseMap=tradeMap(data);
      const isManual=add.trades.some(t=>t.code===code);
      if(!baseMap[code] && !isManual) return json({error:"unknown trade"},400);
      const desc=(b.desc||"").toString().trim().slice(0,300); if(!desc) return json({error:"missing description"},400);
      const baseCount=baseMap[code]?baseMap[code].count:0;
      const manualCount=add.tasks.filter(t=>t.code===code).length;
      const num=baseCount+manualCount+1;
      const tid=code+"-"+String(num).padStart(3,"0");
      const item={code,id:tid,desc,location:(b.location||"").toString().slice(0,120),flag:(b.flag||"").toString().slice(0,40),by:user,at:ts};
      add.tasks.push(item);
      log.push({ts,user,action:"added task",id:tid,label:desc});
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));await kv.put("add:"+id,JSON.stringify(add));
      return json({ok:true,item});
    } else if(b.action==="renametask"){
      const tid=(b.taskId||"").toString(); if(!tid) return json({error:"missing taskId"},400);
      const item=add.tasks.find(t=>t.id===tid); if(!item) return json({error:"unknown task"},400);
      const desc=(b.desc||"").toString().trim().slice(0,300); if(!desc) return json({error:"missing description"},400);
      item.desc=desc;
      item.location=(b.location||"").toString().slice(0,120);
      item.flag=(b.flag||"").toString().slice(0,40);
      log.push({ts,user,action:"renamed task",id:tid,label:desc});
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));await kv.put("add:"+id,JSON.stringify(add));
      return json({ok:true,item});
    } else if(b.action==="renametrade"){
      const code=(b.code||"").toString(); if(!code) return json({error:"missing code"},400);
      const tr=add.trades.find(t=>t.code===code); if(!tr) return json({error:"unknown trade"},400);
      const name=(b.name||"").toString().trim().slice(0,60); if(!name) return json({error:"missing name"},400);
      tr.name=name;
      log.push({ts,user,action:"renamed trade",label:name+" ("+code+")"});
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));await kv.put("add:"+id,JSON.stringify(add));
      return json({ok:true,trade:tr});
    } else if(b.action==="restoretask"){
      const item=b.item; if(!item||!item.id) return json({error:"missing item"},400);
      if(!add.tasks.some(t=>t.id===item.id)){ add.tasks.push(item); }
      log.push({ts,user,action:"restored task",id:item.id});
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));await kv.put("add:"+id,JSON.stringify(add));
      return json({ok:true,add});
    } else if(b.action==="restoretrade"){
      const tr=b.trade; if(!tr||!tr.code) return json({error:"missing trade"},400);
      const tasks=Array.isArray(b.tasks)?b.tasks:[];
      if(!add.trades.some(t=>t.code===tr.code)){ add.trades.push(tr); }
      tasks.forEach(function(tk){ if(tk&&tk.id&&!add.tasks.some(t=>t.id===tk.id)) add.tasks.push(tk); });
      log.push({ts,user,action:"restored trade",label:tr.code});
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));await kv.put("add:"+id,JSON.stringify(add));
      return json({ok:true,add});
    } else if(b.action==="deladd"){
      const tid=(b.taskId||"").toString();
      const tcode=(b.code||"").toString();
      if(tid){ add.tasks=add.tasks.filter(t=>t.id!==tid); delete state[tid];
        log.push({ts,user,action:"removed task",id:tid});
        await kv.put("state:"+id,JSON.stringify(state)); }
      else if(tcode){ const tnames=add.tasks.filter(t=>t.code===tcode).map(t=>t.id);
        tnames.forEach(x=>delete state[x]);
        add.tasks=add.tasks.filter(t=>t.code!==tcode); add.trades=add.trades.filter(t=>t.code!==tcode);
        log.push({ts,user,action:"removed trade",label:tcode});
        await kv.put("state:"+id,JSON.stringify(state)); }
      else return json({error:"nothing to remove"},400);
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));await kv.put("add:"+id,JSON.stringify(add));
      return json({ok:true,add});
    } else if(b.action==="addnote"){
      const tid=(b.taskId||"").toString(); if(!tid) return json({error:"missing taskId"},400);
      const text=(b.text||"").toString().trim().slice(0,2000); if(!text) return json({error:"empty note"},400);
      const isAuto=!!b.auto; const ref=(b.ref||"").toString().slice(0,20);
      if(isAuto&&ref){ const ex=(notes[tid]||[]).find(function(n){return n.auto&&n.ref===ref;}); if(ex) return json({ok:true,note:ex,taskId:tid,dedup:true}); }
      const nid="n"+ts.toString(36)+Math.floor(Math.random()*46656).toString(36);
      const note={id:nid,text,by:user,at:ts,to:Array.isArray(b.to)?b.to.slice(0,24).map(x=>(""+x).slice(0,40)):[],tag:(b.tag||"").toString().slice(0,24),done:false,auto:isAuto,ref:ref};
      if(!notes[tid])notes[tid]=[]; notes[tid].push(note);
      log.push({ts,user,action:"added note",id:tid,label:text.slice(0,80)});
      await kv.put("notes:"+id,JSON.stringify(notes));
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true,note:note,taskId:tid});
    } else if(b.action==="addrfi"){
      const isAuto=!!b.auto; const ref=(b.ref||"").toString().slice(0,20);
      if(isAuto&&ref){ const ex=(rfis.list||[]).find(function(r){return r.auto&&r.ref===ref;}); if(ex) return json({ok:true,rfi:ex,dedup:true}); }
      const subject=(b.subject||"").toString().trim().slice(0,200);
      const question=(b.question||"").toString().trim().slice(0,4000);
      if(!subject&&!question) return json({error:"empty rfi"},400);
      if(!rfis.list)rfis.list=[]; if(!rfis.seq)rfis.seq=0;
      rfis.seq++;
      const rid="r"+ts.toString(36)+Math.floor(Math.random()*46656).toString(36);
      const rfi={id:rid,num:rfis.seq,subject:subject,question:question,by:user,at:ts,
        to:Array.isArray(b.to)?b.to.slice(0,24).map(x=>(""+x).slice(0,40)):[],
        due:(b.due||"").toString().slice(0,20),taskId:(b.taskId||"").toString().slice(0,60),
        ref:ref,priority:(b.priority||"").toString().slice(0,20),
        status:"open",answer:"",answerBy:"",answerAt:0,auto:isAuto};
      rfis.list.push(rfi);
      log.push({ts,user,action:"opened RFI #"+rfi.num,id:rfi.taskId||"",label:subject.slice(0,80)});
      await kv.put("rfis:"+id,JSON.stringify(rfis));
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true,rfi:rfi,rfis:rfis});
    } else if(b.action==="answerrfi"){
      const rid=(b.rfiId||"").toString(); const r=(rfis.list||[]).find(function(x){return x.id===rid;});
      if(!r) return json({error:"no rfi"},400);
      r.answer=(b.answer||"").toString().trim().slice(0,4000);
      r.answerBy=user; r.answerAt=ts; r.status="answered";
      log.push({ts,user,action:"answered RFI #"+r.num,id:r.taskId||"",label:(r.answer||"").slice(0,80)});
      await kv.put("rfis:"+id,JSON.stringify(rfis));
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true,rfi:r,rfis:rfis});
    } else if(b.action==="setrfistatus"){
      const rid=(b.rfiId||"").toString(); const r=(rfis.list||[]).find(function(x){return x.id===rid;});
      if(!r) return json({error:"no rfi"},400);
      const st=(b.status||"").toString(); if(["open","answered","closed"].indexOf(st)<0) return json({error:"bad status"},400);
      r.status=st;
      log.push({ts,user,action:st+" RFI #"+r.num,id:r.taskId||"",label:(r.subject||"").slice(0,80)});
      await kv.put("rfis:"+id,JSON.stringify(rfis));
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true,rfi:r,rfis:rfis});
    } else if(b.action==="delrfi"){
      const rid=(b.rfiId||"").toString(); const before=(rfis.list||[]).length;
      rfis.list=(rfis.list||[]).filter(function(x){return x.id!==rid;});
      if(rfis.list.length!==before){ log.push({ts,user,action:"deleted RFI",id:"",label:""}); }
      await kv.put("rfis:"+id,JSON.stringify(rfis));
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true,rfis:rfis});
    } else if(b.action==="addsubmittal"){
      const title=(b.title||"").toString().trim().slice(0,200); if(!title) return json({error:"title required"},400);
      if(!subs.list)subs.list=[]; if(!subs.seq)subs.seq=0; subs.seq++;
      const sid="s"+ts.toString(36)+Math.floor(Math.random()*46656).toString(36);
      const files=Array.isArray(b.files)?b.files.slice(0,30).map(function(f){return {key:(f.key||"").toString().slice(0,200),name:(f.name||"file").toString().slice(0,180),size:+f.size||0,type:(f.type||"").toString().slice(0,80),at:ts,by:user};}):[];
      const sub={id:sid,num:subs.seq,title:title,spec:(b.spec||"").toString().slice(0,120),
        by:user,at:ts,to:Array.isArray(b.to)?b.to.slice(0,40).map(x=>(""+x).slice(0,40)):[],
        approvers:Array.isArray(b.approvers)?b.approvers.slice(0,10).map(x=>(""+x).slice(0,40)):[],
        due:(b.due||"").toString().slice(0,20),status:"open",files:files,responses:[]};
      subs.list.push(sub);
      log.push({ts,user,action:"sent submittal #"+sub.num,id:"",label:title.slice(0,80)});
      await kv.put("subs:"+id,JSON.stringify(subs));
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      try{ if(env.RESEND_KEY){ const emailBy={}; roster.forEach(function(p){ if(p.email) emailBy[p.name]=p.email; }); const rc=[]; (sub.to||[]).concat(sub.approvers||[]).forEach(function(nm){ const e=emailBy[nm]; if(e&&rc.indexOf(e)<0)rc.push(e); }); const link="https://spireconstructors.com/scope.html"; const html='<p>A submittal was sent to you on the Spire Scope Tracker.</p><p><b>Submittal #'+sub.num+' — '+title+'</b></p>'+((sub.approvers&&sub.approvers.length)?'<p>Approvers: '+sub.approvers.join(", ")+'</p>':'')+'<p><a href="'+link+'">Open the tracker to review</a></p>'; for(const em of rc){ await sendEmail(env,em,"Submittal #"+sub.num+": "+title,html); } } }catch(e){}
      return json({ok:true,submittal:sub,subs:subs});
    } else if(b.action==="submittalrespond"){
      const sid=(b.subId||"").toString(); const sub=(subs.list||[]).find(function(x){return x.id===sid;});
      if(!sub) return json({error:"no submittal"},400);
      const dec=(b.decision||"").toString();
      if(["Approved","Approved as Noted","Revise & Resubmit","Rejected"].indexOf(dec)<0) return json({error:"bad decision"},400);
      if(!sub.responses)sub.responses=[];
      sub.responses=sub.responses.filter(function(r){return r.by!==user;});
      sub.responses.push({by:user,decision:dec,comment:(b.comment||"").toString().slice(0,2000),at:ts});
      if(dec==="Approved"||dec==="Rejected"){ var appr=(sub.approvers&&sub.approvers.length)?sub.approvers:null; if(appr){ var done=appr.every(function(a){return sub.responses.some(function(r){return r.by===a&&(r.decision==="Approved"||r.decision==="Rejected");});}); if(done) sub.status="closed"; } }
      log.push({ts,user,action:dec+" submittal #"+sub.num,id:"",label:(sub.title||"").slice(0,80)});
      await kv.put("subs:"+id,JSON.stringify(subs));
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true,submittal:sub,subs:subs});
    } else if(b.action==="submittaladdfiles"){
      const sid=(b.subId||"").toString(); const sub=(subs.list||[]).find(function(x){return x.id===sid;});
      if(!sub) return json({error:"no submittal"},400);
      if(!sub.files)sub.files=[];
      (Array.isArray(b.files)?b.files:[]).slice(0,30).forEach(function(f){ sub.files.push({key:(f.key||"").toString().slice(0,200),name:(f.name||"file").toString().slice(0,180),size:+f.size||0,type:(f.type||"").toString().slice(0,80),at:ts,by:user}); });
      await kv.put("subs:"+id,JSON.stringify(subs));
      return json({ok:true,submittal:sub,subs:subs});
    } else if(b.action==="setsubstatus"){
      const sid=(b.subId||"").toString(); const sub=(subs.list||[]).find(function(x){return x.id===sid;});
      if(!sub) return json({error:"no submittal"},400);
      const st=(b.status||"").toString(); if(["open","closed"].indexOf(st)<0) return json({error:"bad status"},400);
      sub.status=st;
      await kv.put("subs:"+id,JSON.stringify(subs));
      return json({ok:true,submittal:sub,subs:subs});
    } else if(b.action==="delsubmittal"){
      const sid=(b.subId||"").toString();
      subs.list=(subs.list||[]).filter(function(x){return x.id!==sid;});
      await kv.put("subs:"+id,JSON.stringify(subs));
      return json({ok:true,subs:subs});
    } else if(b.action==="addlog"){
      if(!logs.list)logs.list=[];
      const lid="l"+ts.toString(36)+Math.floor(Math.random()*46656).toString(36);
      const photos=Array.isArray(b.photos)?b.photos.slice(0,40).map(function(p){return {key:(p.key||"").toString().slice(0,200),name:(p.name||"photo").toString().slice(0,180),type:(p.type||"").toString().slice(0,80),at:ts};}):[];
      const entry={id:lid,date:(b.date||"").toString().slice(0,20)||new Date(ts).toISOString().slice(0,10),
        by:user,at:ts,weather:(b.weather||"").toString().slice(0,120),crew:(b.crew||"").toString().slice(0,400),
        notes:(b.notes||"").toString().slice(0,5000),photos:photos,
        to:Array.isArray(b.to)?b.to.slice(0,40).map(x=>(""+x).slice(0,40)):[]};
      logs.list.push(entry);
      log.push({ts,user,action:"posted daily log",id:"",label:(entry.notes||"").slice(0,80)});
      await kv.put("logs:"+id,JSON.stringify(logs));
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true,entry:entry,logs:logs});
    } else if(b.action==="dellog"){
      const lid=(b.logId||"").toString();
      logs.list=(logs.list||[]).filter(function(x){return x.id!==lid;});
      await kv.put("logs:"+id,JSON.stringify(logs));
      return json({ok:true,logs:logs});
    } else if(b.action==="resolvenote"){
      const tid=(b.taskId||"").toString(),nid=(b.noteId||"").toString();
      const arr=notes[tid]||[]; const nt=arr.find(n=>n.id===nid); if(!nt) return json({error:"no note"},400);
      nt.done=!!b.done; nt.doneBy=b.done?user:null; nt.doneAt=b.done?ts:null;
      await kv.put("notes:"+id,JSON.stringify(notes));
      return json({ok:true});
    } else if(b.action==="delnote"){
      const tid=(b.taskId||"").toString(),nid=(b.noteId||"").toString();
      if(notes[tid]){notes[tid]=notes[tid].filter(n=>n.id!==nid); if(!notes[tid].length)delete notes[tid];}
      await kv.put("notes:"+id,JSON.stringify(notes));
      log.push({ts,user,action:"deleted note",id:tid});
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true});
    } else if(b.action==="savemarks"){
      const sh=(b.sheet||"").toString(); if(!sh) return json({error:"missing sheet"},400);
      const shapes=Array.isArray(b.shapes)?b.shapes.slice(0,4000):[];
      if(!shapes.length && !b.cal){ delete marks[sh]; } else { marks[sh]={shapes,cal:b.cal||null,at:ts,by:user}; }
      await kv.put("marks:"+id,JSON.stringify(marks));
      return json({ok:true});
    } else if(b.action==="addperson"){
      const name=(b.name||"").toString().trim().slice(0,60); if(!name) return json({error:"missing name"},400);
      const pid="p"+ts.toString(36)+Math.floor(Math.random()*1296).toString(36);
      const person={id:pid,name,role:(b.role||"").toString().slice(0,60),company:(b.company||"").toString().slice(0,60),phone:(b.phone||"").toString().slice(0,40),email:(b.email||"").toString().slice(0,80),group:(b.group||"team").toString().slice(0,20),by:user,at:ts};
      roster.push(person); await kv.put("roster:"+id,JSON.stringify(roster));
      log.push({ts,user,action:"added person",label:name});
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true,person});
    } else if(b.action==="editperson"){
      const pid=(b.id||"").toString(); const pr=roster.find(x=>x.id===pid); if(!pr) return json({error:"no person"},400);
      ["name","role","company","phone","email","group"].forEach(function(k){ if(b[k]!=null) pr[k]=(""+b[k]).slice(0,80); });
      await kv.put("roster:"+id,JSON.stringify(roster)); return json({ok:true,person:pr});
    } else if(b.action==="delperson"){
      const pid=(b.id||"").toString(); roster=roster.filter(x=>x.id!==pid);
      await kv.put("roster:"+id,JSON.stringify(roster));
      log.push({ts,user,action:"removed person",id:pid});
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true});
    } else if(b.action==="setassign"){
      const tid=(b.taskId||"").toString(); if(!tid) return json({error:"missing taskId"},400);
      const to=Array.isArray(b.to)?b.to.slice(0,20).map(function(x){return(""+x).slice(0,60);}):[];
      const due=(b.due||"").toString().slice(0,20);
      if(!to.length && !due){ delete assign[tid]; } else { assign[tid]={to,due,by:user,at:ts}; }
      await kv.put("assign:"+id,JSON.stringify(assign));
      log.push({ts,user,action:"assigned",id:tid,label:(to.join(", ")+(due?" \u00b7 due "+due:"")).slice(0,80)});
      if(log.length>LOG_KEEP)log=log.slice(-LOG_KEEP);await kv.put("log:"+id,JSON.stringify(log));
      return json({ok:true});
    } else return json({error:"unknown action"},400);

    if(log.length>LOG_KEEP) log=log.slice(-LOG_KEEP);
    await kv.put("log:"+id,JSON.stringify(log));
    return json({ok:true,state,ts});
  }
  return json({error:"method not allowed"},405);
}
